from collections import defaultdict
from math import factorial
from itertools import permutations

n = input().strip()
digits = list(n)
unique_digits = set(digits)
count = defaultdict(int)
for d in digits:
    count[d] += 1

result = set()

for length in range(1, len(digits) + 1):
    for p in permutations(digits, length):
        if p[0] == '0':
            continue
        num = ''.join(p)
        if num not in result:
            temp_count = defaultdict(int)
            for d in p:
                temp_count[d] += 1
            valid = True
            for d in temp_count:
                if temp_count[d] > count[d]:
                    valid = False
                    break
            if valid:
                result.add(num)

print(len(result))
